1. Signal 타입 정의:
```typescript
export type Signal = 'buy' | 'hold' | 'sell';
```

2. scoreToSignal 함수 정의 (spec 기준: 0~33=sell, 34~66=hold, 67~100=buy):
```typescript
export function scoreToSignal(score: number): Signal {
  if (score >= 67) return 'buy';
  if (score >= 34) return 'hold';
  return 'sell';
}
```

3. NewsImpactCardData 인터페이스 정의:
```typescript
export interface NewsImpactCardData {
  id: string;
  headline: string;
  source: string | null;
  published_at: string | null;
  impact_score: number;
  signal: Signal;
  confidence: number;
  affected_sectors: string[];
  affected_stocks: string[];
  ai_summary_general: string;  // 일반인 모드 요약
  ai_summary_expert: string;   // 전문가 모드 요약 (원본 텍스트)
  source_url: string | null;
}
```

4. splitSummary 유틸 함수 정의:
```typescript
/**
 * ai_summary를 general/expert 모드로 분리
 * 현재는 동일 텍스트를 양쪽에 사용 (추후 분리 가능)
 */
export function splitSummary(ai_summary: string | null): { general: string; expert: string } {
  const text = ai_summary ?? '분석 정보가 없습니다.';
  return { general: text, expert: text };
}
```

